INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab6eb6c8-1825-4ab1-b5fc-02b6eae68a88', $q$Scheduling$q$, $q$Build and adjust project timelines, assign tasks to crews and subcontractors, and automatically notify stakeholders when dates change.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab6eb6c8-1825-4ab1-b5fc-02b6eae68a88', $q$Budgeting & job costing$q$, $q$Track estimated vs. actual costs across a project to catch budget overruns early.$q$, 1);
