INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Campaign analytics and reporting$q$, $q$Track opens, clicks, bounces, and unsubscribes to measure campaign performance.$q$, 7);
