INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Costs scale up quickly as contact list size grows$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Is Campaign Monitor free to use?$q$, $q$Campaign Monitor offers a time-limited free trial rather than a permanent free plan, letting new users test the platform before choosing a paid tier.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$What is Campaign Monitor's starting price?$q$, $q$Paid plans start at around $13/month for the Lite tier at low contact volumes, with pricing increasing based on list size and plan tier (Essentials, Premier, Enterprise).$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Who owns Campaign Monitor?$q$, $q$Campaign Monitor is part of Marigold, the company formed when CM Group (which had earlier merged Campaign Monitor with Emma and other brands) rebranded in 2023.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Does Campaign Monitor support marketing automation?$q$, $q$Yes, it offers prebuilt customer journeys, welcome sequences, and behavior-triggered automated emails, alongside transactional email sending.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Is Campaign Monitor good for e-commerce businesses?$q$, $q$It can work for e-commerce use cases, but businesses needing deep, specialized e-commerce automation (like advanced abandoned-cart flows) may find purpose-built e-commerce email platforms offer more depth in that area.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Newsletter campaigns for small businesses$q$, $q$Design and send regular branded newsletters using drag-and-drop templates without needing a designer or developer.$q$, $q$Small business owners and marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Multi-client email management for agencies$q$, $q$Manage email campaigns for multiple client brands with consistent design quality and separate segmented lists.$q$, $q$Marketing and creative agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Automated welcome and lifecycle journeys$q$, $q$Set up automated onboarding sequences and behavior-triggered emails to nurture subscribers over time.$q$, $q$Marketing teams building lifecycle programs$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Transactional and order-related emails$q$, $q$Send receipts, confirmations, and other transactional messages alongside promotional campaigns from one platform.$q$, $q$E-commerce and retail businesses$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Lite$q$, $q$$13/month$q$, $q$monthly or annual$q$, $q$["Drag-and-drop email builder","Custom-coded templates","Unlimited signup forms","Automated emails and prebuilt journeys","Transactional emails"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Essentials$q$, $q$$31/month$q$, $q$monthly or annual$q$, $q$["Unlimited email sends","Priority support","Unlimited AI writing tool access","Unlimited automated emails","Inbox preview testing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Premier$q$, $q$$171/month$q$, $q$monthly or annual$q$, $q$["Premier-level support, including phone support","Advanced engagement segmentation","Send-time optimization","Included website builder"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$Enterprise$q$, $q$Custom / contact sales$q$, $q$annual$q$, $q$["Dedicated account manager","Multi-brand management","Proactive deliverability monitoring","Enterprise security and compliance (e.g., SOC 2)"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Campaign Monitor is an email marketing platform that got its start in 2004 in Sydney, Australia, when web designers Ben Richardson and David Greiner built a tool to help fellow designers send better-looking newsletters to clients. That design-first DNA has stuck: Campaign Monitor has long been known for polished, professionally designed email templates and a drag-and-drop builder that makes it easy to produce on-brand campaigns without writing code.$q$, $q$Over the years the company grew from a bootstrapped Australian startup into a major player in the email marketing space, eventually merging with Emma under Insight Partners to form CM Group, which later rebranded as Marigold in 2023. Campaign Monitor now operates as one of Marigold's core email marketing brands, sitting alongside sibling products aimed at different segments of the market, with its operational base in Nashville, Tennessee.$q$, $q$Today Campaign Monitor positions itself as an email marketing and marketing automation tool for small and mid-sized businesses that want agency-quality design without needing an agency. Its core pitch remains largely unchanged since its early days: beautiful templates, straightforward list management, and clear analytics, now layered with automation journeys, AI-assisted content tools, and transactional email support.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$who-its-for$q$, $q$Who Campaign Monitor Is For$q$, 2, ARRAY[$q$Campaign Monitor is best suited to small and mid-sized businesses, marketing teams, and agencies that care about visual polish and want to send professional-looking newsletters and promotional emails without a steep design or technical learning curve. Its template library and drag-and-drop editor make it a natural fit for retailers, hospitality brands, nonprofits, and creative or marketing agencies managing campaigns for multiple clients.$q$, $q$It also appeals to teams that want to grow into automation gradually — Campaign Monitor offers prebuilt customer journeys, welcome sequences, and behavior-triggered emails, so a business can start with simple broadcast newsletters and layer in automation as needs mature. Agencies in particular value the ability to manage several brands' email programs from one place with consistent, on-brand output.$q$, $q$Marketers who lean on AI-assisted copywriting and subject-line help, and who want built-in tools like send-time optimization or inbox previews on higher tiers, will also find Campaign Monitor's feature set aligned with their workflow, especially if design quality and deliverability guidance matter as much as raw automation complexity.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$who-should-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Campaign Monitor is not the cheapest option for very small lists or hobbyist senders. Unlike some competitors that offer a generous permanent free tier, Campaign Monitor's no-cost access is essentially a time-limited trial, and paid plans can feel pricey relative to bare-bones alternatives once list size grows, particularly after the company's 2025 pricing restructure pushed entry-level costs higher.$q$, $q$Businesses that need deep e-commerce-specific automation (advanced abandoned-cart flows, granular product recommendation engines, or native multi-channel SMS built directly into the platform) may find Campaign Monitor's automation less specialized than platforms built primarily for online retail. Similarly, teams wanting a true all-in-one CRM plus email suite, or complex multi-touch attribution and revenue reporting, may outgrow it.$q$, $q$Budget-conscious solopreneurs, very early-stage startups, or anyone who mainly wants simple broadcast sends with a permanent free plan may be better served by lower-cost or freemium alternatives, reserving Campaign Monitor for when brand-quality design and moderate automation become priorities worth paying for.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Campaign Monitor's core strength is its email design toolkit: a drag-and-drop builder, a library of professionally designed templates, and support for custom-coded templates for teams that want full control over HTML. Contact management includes list segmentation, signup forms, and audience tagging so campaigns can be targeted by behavior or profile data.$q$, $q$On the automation side, the platform offers prebuilt customer journeys, welcome series, and trigger-based automated emails, along with transactional email sending for order confirmations and receipts. Reporting covers standard engagement metrics — opens, clicks, unsubscribes, bounces — and higher tiers add features like send-time optimization and inbox preview testing across email clients.$q$, $q$More recently, Campaign Monitor has added AI-assisted writing tools to help generate subject lines and email copy faster, and Premier and Enterprise tiers extend the platform with advanced segmentation, a bundled website builder, and enterprise-grade support and security options such as SOC 2 compliance for larger organizations.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', $q$the-experience$q$, $q$The Campaign Monitor Experience$q$, 2, ARRAY[$q$Using Campaign Monitor day-to-day tends to feel like working in a clean, design-centric editor rather than a dense marketing-ops dashboard. The interface emphasizes visual campaign building, and long-time users often point to the reliability and polish of its templates as a differentiator against more utilitarian competitors.$q$, $q$Support quality scales with plan tier — entry-level plans get email support, while Essentials and above add priority or phone support, which is a meaningful consideration for teams that need fast help during a campaign launch. Onboarding is generally straightforward for anyone familiar with basic email marketing concepts, though building more sophisticated automation journeys takes more time to learn than the core send-a-newsletter workflow.$q$, $q$Overall, the experience rewards teams that prioritize design consistency and want dependable, professional output without heavy technical overhead, while teams looking for the deepest automation or e-commerce integrations may need to supplement Campaign Monitor with other tools or evaluate whether a more specialized platform fits better.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
