INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f19864e7-5001-4ebd-84f9-5bb40f1b4b22', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Gradebook & SpeedGrader$q$, $q$A flexible gradebook paired with SpeedGrader for annotating submissions, applying rubrics, and giving audio/video or inline feedback quickly.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Modules & Course Design$q$, $q$Course content organized into sequential modules combining pages, files, assignments, and quizzes, with prerequisites and completion requirements.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Canvas Studio$q$, $q$Video creation and hosting tool for embedding lecture videos, interactive video quizzes, and time-stamped comments directly into courses.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Canvas Commons$q$, $q$A shared content repository letting instructors and districts publish and reuse course modules, assessments, and resources across a system.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Discussions & Announcements$q$, $q$Threaded discussion boards and announcement tools for asynchronous class communication and peer interaction.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Quizzes & New Quizzes$q$, $q$Built-in assessment engine supporting multiple question types, timed quizzes, question banks, and item analysis.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Mobile Apps$q$, $q$Native Canvas Student, Canvas Teacher, and Canvas Parent apps for iOS and Android, supporting grading, messaging, and coursework on the go.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$LTI & API Integrations$q$, $q$Open REST API and LTI 1.3 support for connecting Zoom, Google Workspace, Microsoft 365, Turnitin, and publisher content directly into courses.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Mastery Paths$q$, $q$Conditional release rules that deliver different content or remediation paths to students based on their performance on prior assignments.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Analytics & Reporting$q$, $q$Course and institution-level analytics on student engagement, grade trends, and participation to help identify at-risk students.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Modern, intuitive interface that's generally easier to navigate than legacy LMS platforms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Deep LTI and API ecosystem for integrating third-party ed-tech tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Strong native mobile apps for students, teachers, and parents$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Open-source core option available for institutions that want to self-host$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Mature, widely adopted platform with a large community and extensive documentation$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Pricing is not publicly listed and requires contacting sales for a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Advanced capabilities like Studio and Catalog are often separate paid add-ons$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Can be more configuration-heavy than needed for very small course operations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Effective use typically requires a dedicated LMS administrator or IT support$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Notification and communication settings are sometimes described by users as confusing to configure$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Is Canvas LMS free?$q$, $q$Canvas has a free, open-source core edition that institutions can self-host, and Instructure also offers a free 'Canvas Free-for-Teacher' account for individual educators. Most schools and universities, however, subscribe to Instructure's paid, hosted version, which is priced individually per institution.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$How much does Canvas LMS cost?$q$, $q$Instructure does not publish standard pricing for institutional Canvas subscriptions. Costs are quoted based on factors like enrollment size, hosting needs, and add-on products, so schools and districts need to contact Instructure sales for a custom quote.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$What's the difference between Canvas open source and Canvas by Instructure?$q$, $q$Canvas's core code is open source and can be downloaded and self-hosted for free. Canvas by Instructure is the commercially supported, cloud-hosted version, which adds infrastructure management, uptime guarantees, customer support, and access to companion products like Studio and Catalog.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Does Canvas integrate with Zoom, Google Workspace, or Microsoft 365?$q$, $q$Yes. Canvas supports LTI integrations and has native or partner-built connections for tools including Zoom, Google Workspace, Microsoft 365/Teams, Turnitin, and many publisher content providers.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Is there a Canvas mobile app?$q$, $q$Yes. Instructure offers separate Canvas Student, Canvas Teacher, and Canvas Parent apps for iOS and Android, covering coursework, grading, and progress monitoring respectively.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Higher education course delivery$q$, $q$Universities and colleges use Canvas as the primary system for hosting course materials, assignments, grading, and communication across departments and terms.$q$, $q$Colleges and universities$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$K-12 blended and remote learning$q$, $q$School districts deploy Canvas to support in-classroom, blended, and remote instruction, giving teachers and parents a shared view of assignments and progress.$q$, $q$K-12 schools and districts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Individual educator course hosting$q$, $q$Independent teachers and tutors use the free Canvas Free-for-Teacher plan to build and run courses without institutional infrastructure.$q$, $q$Independent teachers and tutors$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Self-hosted, customized deployments$q$, $q$Technically capable institutions download and self-host the open-source Canvas codebase to fully customize and control their LMS environment.$q$, $q$IT teams at tech-forward institutions$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Canvas Free-for-Teacher$q$, $q$Free$q$, NULL, $q$["Individual teacher account","Core course tools (assignments, quizzes, discussions)","Not intended for institutional/district use"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Canvas Open Source$q$, $q$Free (self-hosted)$q$, NULL, $q$["Full core LMS codebase","Self-hosted, self-supported","Requires in-house technical administration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Canvas by Instructure (Institutional)$q$, $q$Custom quote$q$, $q$annual$q$, $q$["Cloud hosting and uptime support","Institution-wide admin and SIS integration","Access to Studio, Catalog, and premium support options","Dedicated customer support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Canvas LMS is a learning management system built by Instructure, originally developed at Brigham Young University before spinning out as an independent product. It has grown into one of the most widely deployed LMS platforms in higher education and K-12 schooling worldwide, competing directly with Blackboard Learn, Moodle, Schoology, and D2L Brightspace.$q$, $q$At its core, Canvas gives instructors a central hub to publish course content, collect assignments, run discussions and quizzes, record grades, and communicate with students. Administrators get tools to manage courses, terms, enrollments, and integrations across an entire school, district, or university system.$q$, $q$Canvas has an open-source heritage: the core codebase is available under an open license and can be self-hosted, while most institutions instead subscribe to Instructure's hosted, commercially supported version, which adds cloud infrastructure, uptime guarantees, support, and companion products like Canvas Studio and Canvas Catalog.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$who-its-for$q$, $q$Who Canvas LMS Is For$q$, 2, ARRAY[$q$Canvas is built for educational institutions rather than individual consumers. Colleges and universities use it as their primary course delivery system, and it is one of the dominant platforms in North American and international higher ed. K-12 school districts also rely on it for blended and remote learning, especially where a modern, mobile-friendly interface matters to teachers and students alike.$q$, $q$It fits organizations that need a centralized system administrators can configure at scale — setting grading policies, terms, roles, and integrations once and rolling them out across many courses and departments. Instructional designers and ed-tech teams who want deep LTI (Learning Tools Interoperability) integration with tools like Zoom, Google Workspace, Microsoft 365, Turnitin, and publisher content also find Canvas's API and app ecosystem a strong fit.$q$, $q$Individual teachers who want to try Canvas without institutional backing can also use it through Instructure's free 'Canvas Free-for-Teacher' offering, making it accessible for tutors, homeschool educators, or instructors piloting the platform before a school-wide rollout.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Canvas is not designed for corporate training, employee onboarding, or customer education use cases — those are better served by dedicated corporate LMS or training platforms, since Canvas's feature set, terminology, and reporting are built around academic terms, courses, and grading rather than compliance tracking or skills certification.$q$, $q$Very small operations — a single tutor, a small course creator, or a solo online instructor selling a handful of classes — will likely find Canvas heavier than necessary, since its administrative depth (terms, sub-accounts, SIS integration) is built for institutional scale, not simple one-off course sales.$q$, $q$Institutions without any dedicated IT or LMS-admin staff may also struggle, since getting real value out of Canvas — SIS integration, single sign-on, gradebook policy configuration, LTI tool provisioning — generally requires ongoing technical administration rather than a plug-and-play setup.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Canvas centers on courses made up of modules, pages, assignments, discussions, and quizzes, all organized in a sequential, easy-to-navigate structure for students. The Gradebook and SpeedGrader tools let instructors grade submissions, leave rubric-based and inline feedback, and track progress across a class efficiently.$q$, $q$Beyond the core course shell, Canvas includes Canvas Studio for video-based assignments and interactive video quizzes, Canvas Commons for sharing and reusing course content across a district or institution, and Mastery Paths for delivering differentiated content based on student performance. A built-in Calendar, Announcements, and Conversations (messaging) tools round out day-to-day communication.$q$, $q$Canvas is also an integration hub: its open REST API and LTI 1.3 support let institutions connect video conferencing, plagiarism detection, publisher textbooks, and analytics tools directly into the course experience, and native mobile apps (Canvas Student, Canvas Teacher, Canvas Parent) extend access to iOS and Android.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$the-canvas-experience$q$, $q$The Canvas LMS Experience$q$, 2, ARRAY[$q$Compared to older-generation systems like Blackboard Learn's legacy interface, Canvas is generally regarded as cleaner and more modern, with a flatter navigation structure and a course layout that's easier for students to pick up with little training. Notifications, to-do lists, and a unified dashboard help students track deadlines across multiple classes.$q$, $q$For instructors, the day-to-day experience revolves around building modules once and reusing them across terms, then leaning on SpeedGrader and rubrics to keep grading consistent. Many users describe the learning curve as moderate: straightforward for basic course delivery, but with real depth once you get into outcomes tracking, Mastery Paths, or advanced gradebook policies.$q$, $q$Overall, the experience is shaped by scale — Canvas is at its best when an institution invests in configuring it well, integrating the tools its faculty already use, and training staff, rather than treating it as an out-of-the-box solution.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
