INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Automatic continuous backup$q$, $q$Once installed, the client detects new and changed files and uploads them in the background without manual intervention.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Encrypted cloud storage$q$, $q$Files are encrypted both in transit and at rest to protect backed-up data from unauthorized access.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Unlimited storage (per computer)$q$, $q$Eligible Carbonite Safe plans back up an entire computer's files without a storage cap, unlike metered cloud storage services.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$External hard drive backup$q$, $q$Plus and Prime plans extend automatic backup coverage to attached external hard drives.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Large video file backup$q$, $q$The Prime plan adds support for backing up larger video files, aimed at users with heavier media libraries.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Courier recovery service$q$, $q$For large restores, Carbonite can ship a physical hard drive containing a customer's backed-up data instead of requiring a full download.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Mobile access$q$, $q$iOS and Android apps let users browse and restore individual backed-up files from a phone or tablet.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Server backup$q$, $q$Business-oriented plans extend automatic backup to physical and virtual servers.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Microsoft 365 backup$q$, $q$Business plans can protect Microsoft 365 mailbox and file data separately from Microsoft's own retention policies.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$File versioning and restore$q$, $q$Previous versions of backed-up files can be restored, helping recover from accidental edits, deletions, or ransomware encryption.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Simple, largely hands-off setup that appeals to non-technical users$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Unlimited storage on eligible per-computer plans, useful for large photo/video libraries$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Established track record dating back to 2005 with strong brand recognition$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Courier recovery service is a practical option for very large restores$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Business tier extends the same backup approach to servers and Microsoft 365$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Pricing is per computer, so protecting many devices can get expensive compared to flat multi-device plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$External hard drive and video file backup are limited to higher-tier plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$No built-in support for backing up NAS devices on standard consumer plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Less granular control over backup rules and scheduling than IT-focused backup tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Initial full backup of large drives can take a long time depending on upload bandwidth$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Is Carbonite free to use?$q$, $q$No, Carbonite is a paid service, though it has historically offered a free trial period so users can test the backup process before subscribing.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Is Carbonite still operating after being acquired by OpenText?$q$, $q$Yes. OpenText acquired Carbonite in 2019, and Carbonite continues to operate as a backup brand within OpenText's data protection and security portfolio, alongside Webroot.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Does Carbonite back up external hard drives?$q$, $q$External hard drive backup is available on Carbonite Safe's higher-tier plans (Plus and Prime), not on the entry-level Basic plan.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$What is Carbonite's courier recovery service?$q$, $q$It's a service where, instead of downloading a large restore over the internet, Carbonite ships a physical hard drive containing the customer's backed-up files directly to them.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Is data backed up with Carbonite encrypted?$q$, $q$Yes, Carbonite encrypts files both during transmission to its servers and while stored in the cloud.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Personal computer backup$q$, $q$Automatically protect documents, photos, and other personal files on a home computer from hardware failure, theft, or accidental deletion.$q$, $q$Home users and individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Small business endpoint and server protection$q$, $q$Back up office computers and physical or virtual servers so a small business can recover quickly after data loss or a ransomware incident.$q$, $q$Small business owners and solo IT admins$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Large media library backup$q$, $q$Use the Prime plan's support for external drives and large video files to protect extensive photo and video collections.$q$, $q$Photographers, videographers, and content creators$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Microsoft 365 data protection$q$, $q$Add an independent backup layer for Microsoft 365 mailboxes and files, separate from Microsoft's native retention settings.$q$, $q$Small organizations relying on Microsoft 365$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Safe Basic$q$, $q$Approx. $6/month$q$, $q$annual$q$, $q$["Unlimited backup for one computer","Automatic continuous backup","Encrypted cloud storage","Anytime file access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Safe Plus$q$, $q$Approx. $9/month$q$, $q$annual$q$, $q$["Everything in Basic","External hard drive backup","Automatic backup of one external drive"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Safe Prime$q$, $q$Approx. $12/month$q$, $q$annual$q$, $q$["Everything in Plus","Large video file backup","Courier recovery service option"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Business (Server / Microsoft 365 backup)$q$, $q$Custom / contact sales$q$, NULL, $q$["Server backup for physical and virtual machines","Microsoft 365 mailbox and file backup","Centralized management for business environments"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Carbonite is a cloud backup service founded in 2005 and headquartered in Boston, Massachusetts. It built its reputation on a simple promise: install a small client on a Windows or Mac computer, let it run in the background, and it will continuously and automatically upload files to encrypted cloud storage so that a hard drive crash, ransomware attack, theft, or accidental deletion doesn't mean permanent data loss. Carbonite was acquired by OpenText in 2019 and now operates as part of OpenText's broader data protection and cybersecurity portfolio, alongside sibling brand Webroot.$q$, $q$The product line spans two audiences. Carbonite Safe covers individuals and very small offices with per-computer backup plans (Basic, Plus, and Prime), while Carbonite's business-oriented offerings extend backup to physical and virtual servers and to Microsoft 365 mailboxes and files. What has historically set Carbonite apart from generic cloud storage (like Dropbox or Google Drive) is that it is purpose-built for backup rather than file sync — it watches designated folders and drives and keeps saving new and changed versions automatically, rather than requiring the user to manually place files into a synced folder.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$who-carbonite-is-for$q$, $q$Who Carbonite Is For$q$, 2, ARRAY[$q$Carbonite is best suited to home users and solo professionals who want a hands-off way to protect the one computer that holds their important documents, photos, and financial records, but who don't want to think about backup schedules, storage buckets, or retention rules once it's set up. Its unlimited-storage-per-computer model (on eligible plans) also appeals to people with large photo or video libraries who don't want to be metered on gigabytes uploaded.$q$, $q$It's also a reasonable fit for small businesses and solo IT admins who need to back up a handful of physical or virtual servers, or who want a straightforward way to protect Microsoft 365 data, without standing up their own backup infrastructure or learning an enterprise-grade backup platform. Because Carbonite has been on the market since the mid-2000s, it also suits buyers who value a long track record and brand recognition over the newest feature set.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Larger organizations with many endpoints, multiple offices, or complex compliance and disaster-recovery requirements will likely outgrow Carbonite's consumer- and SMB-oriented tooling; they are generally better served by enterprise backup and disaster-recovery platforms with centralized, granular policy management across large fleets.$q$, $q$Carbonite is also not the right choice for people looking for a free plan or the cheapest possible way to protect several devices, since pricing is per computer rather than a flat multi-device bundle. Similarly, users who need to back up network-attached storage (NAS) devices, want deep API access for automation, or need fine-grained control over backup rules (custom exclusion patterns, advanced scheduling, versioning policies) may find Carbonite's consumer plans too simplified for their needs.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Carbonite offers automatic, continuous backup: once installed, the client detects new and changed files and uploads them in the background without requiring the user to manually trigger a backup job. Files are protected with encryption both in transit and at rest, and backed-up data can be restored to the original machine or to a new one after a hardware failure, theft, or ransomware incident.$q$, $q$Higher-tier Safe plans (Plus and Prime) add support for backing up external hard drives, and Prime specifically adds support for larger video files, reflecting Carbonite's push upmarket toward users with heavier media storage needs. For situations where restoring a large amount of data over an internet connection would be impractical, Carbonite has long offered a courier recovery service that ships a physical drive containing a customer's backed-up files. On the business side, Carbonite extends the same automatic-backup philosophy to physical and virtual servers and to Microsoft 365 mailbox and file data, giving small organizations a path to protect more than just individual desktops.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$the-carbonite-experience$q$, $q$The Carbonite Experience$q$, 2, ARRAY[$q$Using Carbonite typically starts with downloading a desktop client for Windows or Mac, signing in, and choosing which drives or folders to protect; the software then works quietly in the background, indicating backup status with small icons overlaid on files and folders in Windows Explorer or Finder. This design choice — optimizing for 'install once and forget about it' — is central to Carbonite's appeal to non-technical users, though it also means the interface offers less granular control than backup tools aimed at IT professionals.$q$, $q$When something goes wrong, restoring files is handled either through the desktop client or a web dashboard, and mobile apps for iOS and Android let users browse and retrieve individual backed-up files from a phone or tablet. For catastrophic scenarios — a failed drive with a large backup to restore — the courier recovery option removes the bottleneck of downloading everything over a home internet connection. Overall, the experience trades some flexibility for simplicity and reliability, which is consistent with Carbonite's two-decade positioning as a backup service for people who want protection without becoming backup administrators.$q$]::text[], 4);
