INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Drag-and-block page builder$q$, $q$Build pages by stacking and rearranging pre-built content blocks like text, images, forms, and buttons, with no coding required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Fully responsive output$q$, $q$Every site automatically adapts to desktop, tablet, and mobile, with live previews for each breakpoint while editing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Template gallery$q$, $q$Choose from a wide range of free starter templates for portfolios, link pages, landing pages, and forms, or start from a blank canvas.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Custom domains with free SSL$q$, $q$Paid plans support connecting a custom domain and automatically provision SSL certificates via Let's Encrypt.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Native forms and email integrations$q$, $q$Add contact and signup forms that connect directly to services like Mailchimp, Kit, and ActiveCampaign.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Third-party widgets$q$, $q$Embed widgets for services such as Stripe, Gumroad, and Typeform to add payments, digital products, or surveys without custom code.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Custom CSS support$q$, $q$More advanced users can add custom CSS to individual elements or entire sites for finer design control.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Password protection and redirects$q$, $q$Higher Pro tiers allow password-protecting pages and setting up custom URL redirects.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Site export$q$, $q$Top-tier plans let users download a full copy of their site's underlying files.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Google Analytics integration$q$, $q$Connect Google Analytics on paid plans to track visitor traffic to a published site.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Extremely low cost compared to full website builders, with paid plans starting at just $9/year$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Very fast to learn and use, with pages that can be built and published in minutes$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Clean, lightweight, fast-loading output ideal for link-in-bio and landing pages$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Generous free plan that lets users try the full editor before paying$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Simple, focused editor without the bloat of a full CMS or page-builder platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$No native blog or content management system for multi-page or content-heavy sites$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$No built-in e-commerce checkout — online selling relies on third-party widgets$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Free plan lacks custom domains and forms, limiting it mostly to a subdomain preview$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Design flexibility beyond the block-stacking layout requires writing custom CSS$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Not suited for large, complex, or highly interactive websites$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Is Carrd free to use?$q$, $q$Yes. Carrd offers a free plan that allows up to three sites hosted on a carrd.co subdomain, though it includes a Carrd badge and lacks custom domains and native forms. Paid Pro plans remove these limits and add more features.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$How much does Carrd Pro cost?$q$, $q$Carrd's paid plans are billed annually: Pro Lite starts at $9/year, Pro Standard is $19/year, and Pro Plus is $49/year, with each tier unlocking more sites, features, and integrations.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Can I use a custom domain with Carrd?$q$, $q$Custom domains are supported starting with the Pro Standard plan and above, including free SSL certificates via Let's Encrypt; they are not available on the free plan or Pro Lite.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Can I build an online store with Carrd?$q$, $q$Carrd doesn't have a built-in shopping cart or checkout system, but you can embed third-party payment and product widgets such as Stripe payment links or Gumroad to sell products or services from a Carrd page.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Is Carrd good for a link-in-bio page?$q$, $q$Yes — Carrd is widely used as a customizable alternative to generic link-in-bio tools, since it lets users design a fully branded, mobile-responsive page rather than a fixed list layout.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Link-in-bio pages$q$, $q$Creators and social media users build a single customizable page to house links to their content, shop, and social profiles in place of a generic link aggregator.$q$, $q$Creators, influencers, and social media users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Coming-soon and waitlist pages$q$, $q$Founders launch a fast, simple page to announce an upcoming product and collect email signups before a full site is ready.$q$, $q$Indie makers and early-stage startups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Personal portfolios and resumes$q$, $q$Freelancers and professionals create a lightweight personal site to showcase work samples, a bio, and contact information.$q$, $q$Freelancers and job seekers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Small business landing pages$q$, $q$Local businesses and consultants set up a single page with hours, services, and a contact form without needing a full multi-page website.$q$, $q$Small businesses and consultants$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Free$q$, $q$$0$q$, NULL, $q$["Up to 3 sites","Hosted on a carrd.co subdomain","Core drag-and-block editor","Carrd badge in footer","No custom domain or forms"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Pro Lite$q$, $q$$9$q$, $q$annual$q$, $q$["Up to 3 sites","No Carrd badge","Expanded template access","Increased media upload limits","No custom domain or forms"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Pro Standard$q$, $q$$19$q$, $q$annual$q$, $q$["Up to 10 sites","Custom domain with free SSL","Native forms (Mailchimp, Kit, ActiveCampaign)","Widgets for Stripe, Gumroad, Typeform","Google Analytics integration"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Pro Plus$q$, $q$$49$q$, $q$annual$q$, $q$["Up to 25 sites","Advanced forms","Password-protected pages","Custom redirects and canonical URLs","Downloadable site export files"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Carrd is a simple, free-to-start website builder focused on one thing: helping people create fully responsive single-page sites quickly and cheaply. It was built by a solo web designer known online as AJ, who had previously run the popular free-template site HTML5 UP, and launched Carrd publicly in late 2016 after noticing that one-page templates were by far the most downloaded on his older site. What started as a side project became a self-funded, bootstrapped SaaS business that has grown to host millions of published sites while still being run by a very small team.$q$, $q$Unlike full-scale website builders such as Wix or Squarespace, Carrd deliberately stays narrow in scope. There is no blogging engine, no e-commerce storefront, and no complex page-management system — instead, users pick a starting template (or a blank canvas) and assemble a page from simple, stacked content blocks like text, images, forms, and buttons. That constraint is the product's core selling point: it keeps the builder fast, the output lightweight, and the learning curve almost nonexistent, which is why Carrd is especially popular for link-in-bio pages, personal portfolios, coming-soon pages, and small landing pages.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$who-carrd-is-for$q$, $q$Who Carrd Is For$q$, 2, ARRAY[$q$Carrd is best suited to individuals and small operators who need a single, good-looking page online fast and don't want to pay for or learn a full website platform. This includes freelancers and creators building a personal bio or portfolio page, indie makers launching a coming-soon or waitlist page for a new product, and social media users who want a customizable link-in-bio hub instead of a generic link aggregator. Its extremely low annual pricing (starting at $9/year for the entry Pro tier) also makes it attractive to students, hobbyists, and anyone building throwaway or short-lived project pages.$q$, $q$It's also a good fit for small businesses, event organizers, and consultants whose entire online presence can reasonably live on one scrollable page — think a local service provider listing hours and a contact form, a wedding or event info page, or a simple lead-capture landing page for a marketing campaign. Because Carrd sites are static and load quickly, it's a solid choice for anyone who prioritizes speed and simplicity over rich functionality.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Carrd is not built for multi-page marketing sites, content-heavy blogs, or online stores — there's no native blog engine and no built-in e-commerce checkout (e-commerce is limited to embedding third-party widgets like Stripe payment links or Gumroad buttons). Businesses that need a real content management workflow, multiple authors, or dozens of interlinked pages will quickly outgrow what Carrd is designed to do and should look at a general-purpose builder like Squarespace, Webflow, or WordPress instead.$q$, $q$Teams that need built-in SEO tooling beyond basic meta tags, advanced form logic, membership/gated content, or deep third-party integrations will also find Carrd limiting, since its philosophy is intentionally minimal rather than feature-rich. Similarly, anyone who wants a fully drag-and-drop, pixel-precise design canvas (in the style of Webflow) may find Carrd's block-stacking layout model too rigid for highly custom designs.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Carrd's core interface lets users build pages by stacking pre-built content elements — text, images, embeds, buttons, forms, and galleries — inside customizable sections, with live desktop, tablet, and mobile previews shown side by side as changes are made. It ships with a large library of free starter templates spanning portfolios, link pages, landing pages, and forms, plus the ability to start from a completely blank page for full control over layout and styling.$q$, $q$Paid Pro plans unlock custom domains with free SSL, native forms that connect to email/marketing tools like Mailchimp and ActiveCampaign, Google Analytics integration, and widgets for services such as Stripe, Gumroad, and Typeform. Higher tiers add password-protected pages, custom redirects, downloadable site export files, and support for hosting more sites per account.$q$, $q$Every Carrd site is fully responsive by default and renders as clean, fast-loading static HTML/CSS/JS rather than a heavy app bundle, which keeps page speed high without any manual optimization work. Publishing is instant — there's no separate build or deploy step — and the same editor is used whether a site is on the free plan or a paid tier.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$the-carrd-experience$q$, $q$The Carrd Experience$q$, 2, ARRAY[$q$The overall experience is defined by speed and simplicity: most users can go from a blank template to a published page in minutes, without needing any design or coding background. The editor avoids clutter, and Carrd's documentation and template gallery are geared toward getting non-technical users unstuck quickly rather than exposing deep configuration menus.$q$, $q$That simplicity comes with trade-offs some users notice as their needs grow — there's no native multi-page site structure, no built-in blog, and customization beyond the block system requires dropping into custom CSS, which non-technical users may find intimidating. Still, for its intended use case of small, single-page sites, the experience is consistently praised for being fast, affordable, and low-friction, which is a large part of why it has become a go-to tool for link-in-bio pages and quick landing pages across the indie maker and creator community.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
