INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Interactive Gantt Charts$q$, $q$Drag-and-drop scheduling with automatic critical-path highlighting, task dependencies, and baselines for tracking plan vs. actual.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Resource Management$q$, $q$Visualize utilization and availability across people and skills to plan capacity and avoid overallocation.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Time Tracking & Timesheets$q$, $q$Log hours against tasks and projects, feeding directly into budgets and client billing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Budgeting & Financial Tracking$q$, $q$Track project costs, billing rates, and profitability alongside schedule and resource data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Business Intelligence & Custom Reports$q$, $q$Configurable dashboards and reports for portfolio-wide analytics and cross-project insight.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$No-Code Custom Apps & Workflow Automation$q$, $q$Build custom forms, approval chains, and business processes without developer help.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Client Portal$q$, $q$Give external clients or stakeholders limited visibility into project progress without exposing internal data.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Risk & Issue Tracking$q$, $q$Log and monitor project risks and issues alongside the schedule and resourcing.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Portfolio-Level Views$q$, $q$Compare timelines, budgets, and health across multiple projects at once for PMO-style oversight.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$API & Integrations$q$, $q$Connect Celoxis to other business systems for data sync and workflow extension.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Combines Gantt scheduling, resource management, budgeting, and BI reporting in a single platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Rare choice of cloud or on-premise deployment, useful for data-residency and compliance needs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Deep customization through no-code custom apps and workflow automation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Client portal supports transparent, controlled reporting to external stakeholders$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Long track record as a mature PPM product with two decades of continuous development$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$No permanent free plan; only a 14-day free trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Steeper learning curve and heavier configuration than lightweight kanban-style tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Minimum full-access user requirement can make it costly for very small teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Interface leans more spreadsheet/table-dense than modern visual, card-based tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Top-tier and on-premise/Enterprise pricing requires contacting sales, limiting price transparency$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Does Celoxis have a free plan?$q$, $q$No. Celoxis does not offer a permanent free tier; it provides a 14-day free trial with sample data, and paid plans require a minimum of 5 full-access users.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Can Celoxis be self-hosted or installed on-premise?$q$, $q$Yes. Celoxis is one of the few PPM tools offering both a cloud-hosted subscription and an on-premise installation, letting organizations choose based on data-residency or compliance needs.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$What is Celoxis best known for?$q$, $q$Celoxis is best known for combining Gantt-chart scheduling, resource management, budgeting/financial tracking, and business intelligence reporting for mid-size to enterprise project teams.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Does Celoxis offer an API?$q$, $q$Yes, Celoxis provides an API for integrating project, resource, and financial data with other business systems.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$How is Celoxis priced?$q$, $q$Celoxis uses per-user, per-month pricing across tiers (Core, Essentials, Professional, and Business), billed annually, plus a custom-quoted Enterprise tier; a minimum of 5 full-access users applies.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Enterprise PMO Portfolio Oversight$q$, $q$Compare timelines, budgets, and resource load across dozens of concurrent projects from a single portfolio view.$q$, $q$Enterprise PMOs and IT/engineering leadership$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Client Billing for Professional Services$q$, $q$Track billable hours, project budgets, and profitability, then share progress with clients through a controlled client portal.$q$, $q$Agencies, consultancies, and services firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Custom Workflow & App Building$q$, $q$Use the no-code app builder and workflow automation to model approval chains and processes unique to the organization.$q$, $q$Operations and IT teams standardizing internal processes$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Regulated or Data-Sensitive Deployments$q$, $q$Run Celoxis on-premise to keep project and financial data inside the organization's own infrastructure.$q$, $q$Government contractors and regulated enterprises$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Core$q$, $q$$10/user/month$q$, $q$annual$q$, $q$["Task & project management","Gantt charts","Basic reporting","2 free read-only users","5 full-access user minimum"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Essentials$q$, $q$$25/user/month (Standard user)$q$, $q$annual$q$, $q$["Resource management","Custom fields","Time tracking & timesheets","5 free read-only users"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Professional$q$, $q$$35/user/month (Standard user)$q$, $q$annual$q$, $q$["Budgeting & financial tracking","Client portal","Advanced BI reporting","10 free read-only users"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["On-premise deployment option","Advanced security & SSO","Custom SLAs","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Celoxis is a project portfolio management (PPM) platform built by Celoxis Technologies, an India-founded software company established in 2001 and headquartered in Pune. Long positioned as an alternative to lightweight task boards, Celoxis targets organizations that need to manage many concurrent projects rather than a single to-do list, pairing traditional Gantt-chart scheduling with resource planning, budgeting, and business intelligence in one system.$q$, $q$What distinguishes Celoxis from most modern SaaS project tools is its dual deployment model: customers can run it as a hosted cloud subscription or install it on their own servers on-premise, an option most competitors dropped years ago. This makes it a recurring shortlist pick for regulated industries, government contractors, and enterprises with data-residency requirements. Under the hood, Celoxis bundles interactive Gantt charts with critical-path and dependency management, resource utilization and capacity planning, time tracking and timesheets, financial and budget tracking, no-code custom business apps, workflow automation, and configurable BI-style dashboards and reports.$q$, $q$Celoxis is sold purely as paid software with a 14-day free trial rather than a permanent free tier, and pricing scales per user across several tiers plus a custom Enterprise plan. It competes most directly with other PPM-oriented tools such as Microsoft Project, Planview, and Smartsheet, rather than with simpler kanban-first tools like Trello.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$who-celoxis-is-for$q$, $q$Who Celoxis Is For$q$, 2, ARRAY[$q$Celoxis is best suited to mid-size and enterprise organizations running a portfolio of projects at once rather than a single initiative — IT departments, engineering groups, construction and professional-services firms, and PMOs (project management offices) that need to compare timelines, budgets, and resource load across many projects side by side. Its Gantt-first, dependency-aware scheduling model appeals to project managers who plan formally and need critical-path visibility rather than teams that just want a lightweight shared checklist.$q$, $q$Organizations that bill clients for time and need to track budgets, costs, and profitability project-by-project — agencies, consultancies, and services firms — get particular value from Celoxis's built-in financial tracking, timesheets, and client-portal features. It also suits IT and operations teams that want to build custom, no-code internal applications and approval workflows on top of their project data, and any organization with strict data-residency, security, or compliance needs that requires an on-premise deployment rather than a public cloud SaaS tool.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Small teams, startups, and freelancers looking for a simple, inexpensive way to track tasks will likely find Celoxis more tool than they need. There is no permanent free plan, per-user pricing carries a minimum-seat requirement, and the depth of scheduling, budgeting, and reporting features adds a learning curve that outweighs the benefit for a handful of people managing a handful of projects.$q$, $q$Teams that want a highly visual, kanban-first, drag-and-drop experience akin to Trello or Asana may also find Celoxis's Gantt-and-spreadsheet-oriented interface feels more like traditional enterprise PM software than a modern lightweight app. Likewise, organizations unwilling to invest time in initial configuration — setting up custom fields, workflows, resource calendars, and permission structures — may not see Celoxis's advantages pay off quickly, since much of its value comes from tailoring it to how the organization actually runs projects.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Celoxis offers interactive Gantt charts with automatic critical-path highlighting, task dependencies, baselines, and drag-and-drop rescheduling, alongside portfolio-level views that let PMOs compare multiple projects' timelines and health at once. Resource management tools show utilization and availability across people and skills, helping managers avoid overallocating staff, while built-in timesheets tie logged hours back to tasks, projects, and budgets.$q$, $q$Financial tracking covers project budgets, costs, billing rates, and profitability, which — combined with a client portal — makes it possible for services firms to give clients visibility into progress without exposing internal data. Celoxis also includes a no-code custom application builder and workflow-automation engine, letting administrators create tailored forms, approval chains, and business processes without a developer, plus configurable, BI-style dashboards and reports for portfolio analytics and cross-project insight.$q$, $q$Rounding things out are risk and issue tracking, discussion and collaboration tools attached to tasks, document management, and an API for integrating with other business systems, giving Celoxis the breadth expected of an enterprise PPM suite rather than a single-purpose task tracker.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$the-celoxis-experience$q$, $q$The Celoxis Experience$q$, 2, ARRAY[$q$Long-time reviewers of Celoxis consistently describe it as feature-dense and configuration-heavy: the payoff for investing time in setup is a system that can genuinely model how a real PMO or services organization runs its projects, but that same depth means new users and admins face a steeper learning curve than with lightweight task-board apps. Its interface leans toward dense tables, Gantt views, and report builders rather than the highly visual card-and-board style popularized by Trello or Asana.$q$, $q$Because Celoxis has offered both cloud and on-premise deployment for two decades, it has a reputation for stability and for serving customers with long procurement cycles — enterprises, government, and regulated industries — who value that flexibility over flashy design. Customer support and onboarding assistance are commonly cited as strengths in independent reviews, which matters given the configuration involved in getting the most out of the platform.$q$, $q$Overall, the Celoxis experience rewards teams that need genuine project-portfolio and financial rigor and are willing to trade some ease-of-entry for that capability, rather than teams looking for the fastest possible time-to-first-task.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Teambook Kanban task board$q$, $q$A built-in Kanban-style board lets teams turn any chat message into a task with assignees, due dates, and priority levels, without needing a separate project management app.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Unlimited group chats and channels$q$, $q$Public and private channels and direct messages are unlimited on every plan, including the free tier.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Audio and video calling with screen sharing$q$, $q$One-on-one calls are free on every plan, while paid plans add group audio/video calls and screen sharing for larger meetings.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Voice messages$q$, $q$Team members can send short voice recordings directly in chat as an alternative to typing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Searchable unified message history$q$, $q$All conversations, files, and tasks are indexed and searchable, with no history limit even on the free plan.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$File sharing and storage$q$, $q$Teams can share and store files directly in conversations, with storage allowances that scale by plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Integrations$q$, $q$Connects with popular tools such as Google Drive, Trello, Zapier, and GitHub, with the integration count capped on the free plan and unlimited on paid plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Roles, permissions, and employee directory$q$, $q$Paid plans add customizable member roles, permissions, and a searchable employee directory for larger teams.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Security and compliance controls$q$, $q$Business and Enterprise plans support SSO, two-factor authentication, IP allowlisting, data retention policies, and HIPAA-compliant configurations.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Cross-platform apps$q$, $q$Native apps are available for web, Windows, Mac, Linux, iOS, and Android so teams can stay connected from any device.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Lower per-user pricing than Slack or Microsoft Teams on comparable plans$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Built-in Kanban task board (Teambook) removes the need for a separate project management tool$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Simple, uncluttered interface with a shorter learning curve for non-technical teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Generous free plan with unlimited message history and 20GB of storage$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Cross-platform coverage including native web, desktop, and mobile apps$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Smaller integration and app ecosystem than Slack or Microsoft Teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Free plan is capped at 5 team members, which limits it for growing teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Lacks native AI-powered summarization or an in-chat AI assistant found in some newer competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Less brand recognition means fewer third-party tutorials, templates, and community resources$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Enterprise-grade governance and customization options are less mature than long-established competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Is Chanty free to use?$q$, $q$Yes. Chanty offers a Free Forever plan for up to 5 team members with unlimited chats, searchable history, and 20GB of team storage. Paid Business and Enterprise plans remove the member cap and add features like screen sharing and advanced permissions.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$What is Teambook in Chanty?$q$, $q$Teambook is Chanty's built-in Kanban-style task management board. It lets teams create tasks directly from chat messages, assign them, set deadlines and priorities, and track progress without leaving the app.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$How does Chanty's pricing compare to Slack?$q$, $q$Chanty's Business plan starts at $3 per user/month billed annually (or $4/month billed monthly), which is generally lower than comparable paid tiers from Slack or Microsoft Teams, making it a common choice for budget-conscious small businesses.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Does Chanty support video calls and screen sharing?$q$, $q$Yes. One-on-one audio and video calls are available on every plan, including free, while paid plans add group audio/video calls and screen sharing for team meetings.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Is Chanty available on desktop and mobile?$q$, $q$Yes. Chanty offers native apps for web, Windows, Mac, Linux, iOS, and Android, so teams can communicate and manage tasks from any device.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$All-in-one chat and task tracking for small teams$q$, $q$Teams use Chanty's chat and Teambook Kanban board together so conversations and their resulting action items stay in one place instead of a separate PM tool.$q$, $q$Small businesses and startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Cost-effective Slack replacement$q$, $q$Cost-conscious teams switch from Slack or Microsoft Teams to Chanty's lower per-user Business plan to reduce software spend while keeping core chat and calling features.$q$, $q$Budget-conscious growing companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Remote and distributed team coordination$q$, $q$Distributed teams rely on Chanty's channels, voice messages, and group video calls to stay aligned across time zones without in-person meetings.$q$, $q$Remote-first and hybrid teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Lightweight agency and service-business collaboration$q$, $q$Agencies and service businesses use Teambook to manage client work and internal projects directly alongside day-to-day team chat.$q$, $q$Agencies and small service businesses$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Free$q$, $q$$0$q$, NULL, $q$["Up to 5 team members","Unlimited public and private conversations","Unlimited searchable message history","20GB of storage per team","One-on-one audio/video calls","Built-in task management (Teambook)","Up to 10 integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Business$q$, $q$$3 per user/month billed annually, or $4 per user/month billed monthly$q$, $q$monthly or annual$q$, $q$["Unlimited team members","Unlimited group audio/video calls and screen sharing","Task boards and unlimited channels","Employee directory and calendar/events","Customizable roles and permissions","Data import/export","HIPAA-compliant configuration and SSO/2FA","24/7 priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["Everything in Business","White labeling","SAML/SSO and SCIM provisioning","Enterprise API and unlimited integrations","On-premise deployment option","Advanced permissions and unlimited custom roles","Dedicated customer success manager and SLA-backed support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Chanty is a team communication and collaboration platform founded in 2017 by Dmytro Okunyev, built around the idea that small and mid-sized teams need the core value of Slack or Microsoft Teams without the price tag, feature bloat, or steep learning curve. At its heart, Chanty is a chat app: unlimited public and private conversations, threaded discussions, voice messages, and searchable history are all included even on the free tier.$q$, $q$What sets Chanty apart from a plain messaging app is Teambook, a built-in Kanban-style task board that lives inside the same interface as the chat. Teams can turn any message into a task with a click, assign it, set a deadline and priority, and track it through a board without ever opening a separate project management tool. Audio and video calling, screen sharing, and a growing set of integrations round out the platform.$q$, $q$Chanty is offered as a freemium SaaS product with web, desktop (Windows, Mac, Linux), and mobile (iOS, Android) apps, and it carries security and compliance credentials including SOC 2, ISO 27001, GDPR, and HIPAA support, which has helped it gain traction with businesses that need a lightweight but auditable communication tool.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$who-chanty-is-for$q$, $q$Who Chanty Is For$q$, 2, ARRAY[$q$Chanty is best suited to small businesses, startups, and small-to-mid-sized teams that want one tool to handle both day-to-day conversation and lightweight task tracking, rather than paying for and stitching together separate chat and project management subscriptions. Its per-user pricing on the Business plan is meaningfully lower than Slack's or Microsoft Teams' comparable tiers, which makes it attractive to budget-conscious teams of roughly 5 to 100 people.$q$, $q$It also appeals to teams that find Slack or Teams overwhelming. Chanty's interface is deliberately simpler, with fewer configuration options and a shorter onboarding curve, so non-technical teams (agencies, service businesses, remote-first small companies) can get a group up and running quickly. Teams that specifically want task management built into the chat, instead of relying on a Trello or Asana integration, are a strong fit for the Teambook feature.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with complex workflow, compliance, or integration requirements may find Chanty's ecosystem thinner than Slack's or Microsoft Teams', which offer thousands of App Directory integrations, mature developer platforms, and deeper enterprise governance tooling built up over many more years in market.$q$, $q$Organizations that are already deeply invested in the Microsoft 365 or Google Workspace ecosystem may get more value from Teams or Google Chat, since those tools integrate natively with the productivity suite the company already uses. Similarly, teams that need advanced, AI-native features such as automatic thread summarization or an in-chat AI assistant will find Chanty's current feature set lighter in this area than some newer entrants and than Slack AI.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Chanty's feature set centers on three pillars: messaging, task management, and calls. Messaging includes unlimited public and private channels and direct messages, voice messages, scheduled and disappearing messages, and unified search across the entire message history, even on the free plan.$q$, $q$Teambook, Chanty's built-in Kanban board, lets any message be converted into a task with assignees, due dates, and priority levels, and it supports multiple boards for organizing different projects or workflows without leaving the app. Calling features include one-on-one audio/video on the free plan and group audio/video calls with screen sharing on paid plans, supporting large group calls suitable for company-wide meetings.$q$, $q$Paid plans add an employee directory, calendar and events, polls and forms, customizable roles and permissions, data import/export, and enterprise-grade options like SSO, two-factor authentication, IP allowlisting, and HIPAA-compliant configurations. Integrations connect Chanty to common tools like Google Drive, Trello, Zapier, and GitHub, with the number of connected integrations capped on the free tier and unlimited on paid plans.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$the-chanty-experience$q$, $q$The Chanty Experience$q$, 2, ARRAY[$q$Day to day, using Chanty feels closer to a simplified Slack than a heavyweight enterprise suite: channels and direct messages sit in a familiar left-hand sidebar, and the Teambook tab is one click away so conversations and the tasks that come out of them stay connected rather than living in two disconnected tools.$q$, $q$New users generally report a fast setup and a gentler learning curve than Slack or Teams, in part because Chanty exposes fewer settings and less configuration surface area. That simplicity is a deliberate trade-off: teams that want extensive customization, an app marketplace, or deep third-party AI tooling may eventually outgrow it, but for small teams that primarily need reliable chat plus basic task tracking at a low per-seat cost, the experience is generally described as straightforward and low-friction rather than sparse.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
